function checkPrime(arr) {
    for (let i = 0; i < arr.length; i++) {
        let num = arr[i];
        if (num > 1) {
            for (let j = 2; j < num; j++) {
                if (num % j === 0) {
                    break;
                }
            }
            if (j === num) {
